def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1.2:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        decay_rate = 0.7
        weight = 1.5
        for depth in range(1, 7):
            if residual <= 0:
                score += (20 / depth) * np.exp(-depth/3)
            else:
                score += ((1 / residual) * (depth ** 1.2)) * weight
            residual *= decay_rate
            if depth % 2 == 0:
                weight *= 0.9
            else:
                weight *= 1.1
        if capacity > 4 * item:
            score *= 0.75
        elif capacity > 3 * item:
            score *= 0.85
        elif capacity > 1.5 * item:
            score *= 1.05
        else:
            score *= 1.25
        penalty = 0
        for check in range(1, int(np.ceil(item)) + 3):
            mod_val = (capacity - check) % (check + 1)
            if mod_val == 0:
                penalty += 0.3 * (check ** 1.1)
            elif mod_val % 2 == 0:
                penalty -= 0.15 * (check ** 1.05)
            else:
                penalty += 0.05 * (check ** 0.9)
        score += penalty
        if score < 0:
            priorities[i] = 0
        elif score > 200:
            priorities[i] = 200
        else:
            priorities[i] = score
    return priorities
